import React, { useState } from "react";
import EeshaWalkComponent from "../components/EeshaWalkComponent";
import NavBar from "../components/NavBar";
import "../styles/circles.css";
import "./WalkScreen.css";

export default function WalkScreen() {
  const [walking, setWalking]     = useState(false);
  const [audioCtx, setAudioCtx]   = useState(null);
  const [soundType, setSoundType] = useState("click");

  // AudioContext MUST be created inside a synchronous click handler —
  // browsers suspend it if created outside a user gesture (e.g. in useEffect).
  const handleStart = () => {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    ctx.resume(); // unlock in case browser still suspends it
    setAudioCtx(ctx);
    setWalking(true);
  };

  const handleStop = () => {
    if (audioCtx) {
      audioCtx.close();
      setAudioCtx(null);
    }
    setWalking(false);
  };

  return (
    <div className="walk-screen">
      <div className="circle circle-a" />
      <div className="circle circle-b" />

      <div className="walk-header">
        <div className="logo">synova</div>
        <div className="walk-title">ParkiStep</div>
      </div>

      {walking && audioCtx ? (
        <EeshaWalkComponent
          audioCtx={audioCtx}
          soundType={soundType}
          onStop={handleStop}
        />
      ) : (
        <div className="walk-setup">
          <div className="walk-icon-wrap">
            <div className="pulse-ring" />
          </div>

          <div className="walk-cue">Select sound, then start sensors.</div>

          <div className="cadence-wrap">
            <div className="cadence-label">Sound Profile</div>
            <div className="cadence-picker">
              {[
                { key: "click", label: "Metronome" },
                { key: "wood",  label: "Woodblock"  },
                { key: "bell",  label: "Soft Bell"  },
                { key: "bass",  label: "Bass Drum"  },
              ].map(({ key, label }) => (
                <button
                  key={key}
                  className={`cadence-btn ${soundType === key ? "cadence-btn--active" : ""}`}
                  onClick={() => setSoundType(key)}
                >
                  {label}
                </button>
              ))}
            </div>
          </div>

          <button className="walk-start-btn" onClick={handleStart}>
            START SENSORS
          </button>
        </div>
      )}

      {!walking && <NavBar />}
    </div>
  );
}
